    .sched-inputs { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 15px; }
    .user-profile { margin-top: auto; display: flex; align-items: center; gap: 12px; padding-top: 20px; border-top: 1px solid rgba(255,255,255,0.1); }
    .avatar { width: 35px; height: 35px; background: var(--primary); border-radius: 50%; display: grid; place-items: center; font-weight: bold; }
