  `]
})
export class HrDashboardComponent implements OnInit, OnDestroy {
  // Data State
  title = ''; location = ''; ctc = ''; description = ''; companyName = '';
  internships: any[] = []; applications: any[] = [];
  interviewerList: any[] = []; scheduleData: any = {};
  selectedCandidate: any = null; offerFiles: any = {};
  uploadedOfferForApp: Record<string, string> = {};
  onboardingList: any[] = []; employeeList: any[] = [];
  pdfFile: any = null; uploadedFileName = ''; pdfUploaded = false;
  lastUploadDebug: any = null;

  private intervalId: any;
  private pollingPaused = false;
  private refreshTimer: any;

  constructor(public auth: AuthService, private http: HttpClient, public router: Router) {}

  // Lifecycle Hooks (FIXED: Property missing error)
  ngOnInit() {
    if (!this.auth.user || this.auth.user.role !== 'HR') {
      this.router.navigate(['/']);
      return;
    }
    this.fetchAll();
    this.startPolling();
  }

  ngOnDestroy() {
    this.stopPolling();
  }

  // Core Data Logic
  private fetchAll() {
    const y = window.scrollY || 0;
    Promise.all([
      this.fetchInternships(),
      this.fetchApplications(),
      this.fetchOnboarding(),
      this.fetchEmployees()
    ]).finally(() => { setTimeout(() => window.scrollTo(0, y), 0); });
  }

  async fetchInternships() { this.internships = await this.http.get<any[]>('http://localhost:8080/api/internships').toPromise() || []; }
  async fetchApplications() { this.applications = await this.http.get<any[]>('http://localhost:8080/api/applications').toPromise() || []; }
  async fetchOnboarding() { this.onboardingList = await this.http.get<any[]>('http://localhost:8080/api/onboarding').toPromise() || []; }
  async fetchEmployees() { this.employeeList = await this.http.get<any[]>('http://localhost:8080/api/employees').toPromise() || []; }

  // Polling Management
  startPolling() {
    this.stopPolling();
    this.intervalId = setInterval(() => { if (!this.pollingPaused) this.fetchAll(); }, 8000);
  }
  stopPolling() { if (this.intervalId) { clearInterval(this.intervalId); this.intervalId = null; } }
  pausePolling() { this.pollingPaused = true; }
  resumePolling() { this.pollingPaused = false; }

  // Internship Posting Logic
  onPdfSelected(e: any) { this.pdfFile = e.target.files?.[0]; }
  async handlePdfUpload() {
    if (!this.pdfFile) return alert('Select PDF');
    try {
      const form = new FormData();
      form.append('file', this.pdfFile);
      const res = await this.http.post('http://localhost:8080/api/internships/upload-pdf', form, { responseType: 'text' }).toPromise();
      this.uploadedFileName = res as string;
      this.pdfUploaded = true;
      alert('PDF Uploaded Successfully');
    } catch (err) { alert('Error uploading PDF'); }
  }

  async handlePost() {
    const form = new FormData();
    form.append('companyName', this.companyName); form.append('title', this.title);
    form.append('location', this.location); form.append('ctc', this.ctc);
    form.append('description', this.description); form.append('pdfFileName', this.uploadedFileName);
    await this.http.post('http://localhost:8080/api/internships/post', form).toPromise();
    this.resetForm(); this.fetchInternships();
  }
  resetForm() { this.title = this.location = this.ctc = this.description = this.companyName = ''; this.pdfUploaded = false; this.pdfFile = null; }
  async handleDelete(id: any) { await this.http.delete(`http://localhost:8080/api/internships/${id}`).toPromise(); this.fetchInternships(); }

  // Interview & Results Logic
  getInterviewerName(id: number) {
    if (!id) return '';
    const known: Record<number, string> = { 1: 'Kavya', 2: 'Arun', 3: 'Divya' };
    if (known[id]) return known[id];
    const emp = this.employeeList.find(e => (e.id ?? e.interviewerId) === id);
    return emp ? (emp.name ?? emp.fullName) : '';
  }

  async updateHrResult(id: any, result: string) {
    this.pausePolling();
    const y = window.scrollY;
    try {
      await this.http.post('http://localhost:8080/api/applications/hr-result', null, { params: new HttpParams().set('applicationId', id).set('result', result), responseType: 'text' }).toPromise();
      this.fetchAll();
    } catch (err) { alert('Error updating HR result'); }
    finally { this.resumePolling(); setTimeout(() => window.scrollTo(0, y), 0); }
  }

  // Offer Letter Logic
  handleOfferFileChange(id: any, event: any) { this.offerFiles[id] = event.target.files?.[0]; }
  async uploadOfferLetter(id: any) {
    const file = this.offerFiles[id];
    if (!file) return alert('Select offer letter');
    const form = new FormData(); form.append('applicationId', id); form.append('file', file);
    await this.http.post('http://localhost:8080/api/applications/upload-offer-letter', form, { responseType: 'text' as 'json' }).toPromise();
    alert('Offer uploaded'); this.fetchAll();
  }

  // Scheduling Helpers
  setScheduleValue(appId: any, field: string, value: any) { this.scheduleData[appId] = { ...(this.scheduleData[appId] || {}), [field]: value }; }
  getScheduleValue(appId: any, field: string) { return this.scheduleData[appId]?.[field] || ''; }

  showScheduleOptions(app: any) {
    return (app.status === 'TEST_PASSED' && app.interviewStatus !== 'L1_SCHEDULED') ||
           (app.status === 'L2_PENDING' && app.interviewStatus !== 'L2_SCHEDULED') ||
           (app.status === 'HR_PENDING' && app.interviewStatus !== 'HR_SCHEDULED') ||
           app.l1InterviewerStatus === 'REJECTED' || app.l2InterviewerStatus === 'REJECTED';
  }

  scheduleLabel(app: any) {
    return app.status === 'TEST_PASSED' ? 'Schedule L1' : app.status === 'L2_PENDING' ? 'Schedule L2' : 'Schedule HR';
  }

  async scheduleInterview(appId: any, status: any) {
    const data = this.scheduleData[appId];
    if (!data?.date || !data?.mode) return alert('Fill all fields');
    const params = new HttpParams().set('applicationId', appId).set('level', status === 'TEST_PASSED' ? 'L1' : status === 'L2_PENDING' ? 'L2' : 'HR').set('date', data.date).set('time', data.time || '10:00').set('mode', data.mode).set('interviewerId', data.interviewerId || '');
    await this.http.post('http://localhost:8080/api/applications/schedule-interview', null, { params, responseType: 'text' }).toPromise();
    this.fetchAll();
  }

  interviewerOptionsForApp(app: any) {
    const fallback = [{ id: 1, name: 'Kavya' }, { id: 2, name: 'Arun' }, { id: 3, name: 'Divya' }];
    const list = this.employeeList.filter(e => e.isInterviewer || (e.role && e.role.includes('Interviewer'))).map(e => ({ id: e.id, name: e.name }));
    return list.length ? list : fallback;
  }

  // Onboarding Helpers
  getOnboardingRecord(app: any) { return this.onboardingList.find(ob => ob.applicationId === app.id); }
  statusColor(s: string) { return s === 'VERIFIED' ? 'green' : s === 'REJECTED' ? 'red' : 'orange'; }
  employeeExists(email: string) { return !!this.employeeList.find(emp => emp.email === email); }

  // Formatting & UI
  formatDate(ds: any) { return ds ? new Date(ds).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' }) : ''; }
  formatTime(t: string) { if (!t) return ''; const [h, m] = t.split(':'); const d = new Date(); d.setHours(+h, +m); return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }); }
  scrollTo(id: string) { document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' }); }
  logout() { this.auth.logout(); this.router.navigate(['/']); }
}
